// Walk web/dist and generate dist/static-embed.generated.ts — a module that uses
// Bun's `import ... with { type: 'text' }` attribute so the bytes are inlined
// into the `bun build --compile` binary.
//
// The artifact lives OUTSIDE src/ (in the gitignored repo-root dist/) on purpose:
// `src/static-embed.ts` is a permanent committed empty stub that esbuild / dev /
// typecheck consume, while the Bun compile path redirects to this generated file
// via an onResolve plugin (see server/scripts/release/build-target.mjs). This is
// what lets multiple targets build in parallel without writing a shared file —
// Phase1 generates this once, Phase2 targets only read it.
import { readdirSync, statSync, writeFileSync, existsSync, mkdirSync } from 'node:fs'
import { resolve, relative, posix, dirname, extname } from 'node:path'
import { fileURLToPath } from 'node:url'

const here = dirname(fileURLToPath(import.meta.url))
const repoRoot = resolve(here, '..', '..')
const webDist = resolve(repoRoot, 'web', 'dist')

// Output: repo-root dist/static-embed.generated.ts (gitignored). Override with
// STATIC_EMBED_OUT (absolute path) if a build needs a different snapshot location.
const out = process.env.STATIC_EMBED_OUT
  ? resolve(process.env.STATIC_EMBED_OUT)
  : resolve(repoRoot, 'dist', 'static-embed.generated.ts')

if (!existsSync(resolve(webDist, 'index.html'))) {
  console.error(
    `[generate-static-embed] web/dist/index.html missing — run \`pnpm -F @ccc/web build\` first.`,
  )
  process.exit(1)
}

const MIME = {
  '.html': 'text/html; charset=utf-8',
  '.js': 'application/javascript; charset=utf-8',
  '.mjs': 'application/javascript; charset=utf-8',
  '.css': 'text/css; charset=utf-8',
  '.svg': 'image/svg+xml; charset=utf-8',
  '.json': 'application/json; charset=utf-8',
  '.txt': 'text/plain; charset=utf-8',
  '.map': 'application/json; charset=utf-8',
}

function walk(dir) {
  const out = []
  for (const entry of readdirSync(dir)) {
    const full = resolve(dir, entry)
    if (statSync(full).isDirectory()) {
      out.push(...walk(full))
    } else {
      out.push(full)
    }
  }
  return out
}

const files = walk(webDist).sort()
if (files.length === 0) {
  console.error('[generate-static-embed] no files in web/dist')
  process.exit(1)
}

const outDir = dirname(out)
const imports = []
const entries = []

files.forEach((file, i) => {
  const ext = extname(file)
  const mime = MIME[ext]
  if (!mime) {
    console.error(
      `[generate-static-embed] no MIME mapping for "${ext}" (file: ${file}). Extend MIME table.`,
    )
    process.exit(1)
  }
  // Import path relative to the generated file's own directory (dist/) so Bun
  // resolves the asset bytes at compile time: dist/ → ../web/dist/...
  const importRel = './' + posix.join(relative(outDir, file).split(/[\\/]/).join('/'))
  const ident = `asset${i}`
  imports.push(`import ${ident} from '${importRel}' with { type: 'text' };`)
  // URL path: leading slash, posix separators
  const urlPath = '/' + relative(webDist, file).split(/[\\/]/).join('/')
  entries.push(`  ['${urlPath}', { body: ${ident}, mime: '${mime}' }],`)
})

const body = `// AUTO-GENERATED by server/scripts/generate-static-embed.mjs — do not edit, do not commit.
// Source: web/dist/. Consumed only by the Bun \`--compile\` path via an onResolve
// redirect (server/scripts/release/build-target.mjs). esbuild/dev/typecheck use
// the committed empty stub at server/src/static-embed.ts instead.
// @ts-nocheck — \`with { type: 'text' }\` attribute is a Bun extension; TS lacks declarations.
${imports.join('\n')}

export const STATIC_ASSETS: ReadonlyMap<string, { body: string; mime: string }> = new Map([
${entries.join('\n')}
]);
`

mkdirSync(outDir, { recursive: true })
writeFileSync(out, body)
console.log(`[generate-static-embed] wrote ${files.length} asset(s) → ${out}`)
